"""RAG Knowledge Base — Moroccan Comprehensive Awareness for YAQEEN"""
import re, json, unicodedata

class MoroccoRAG:
    def __init__(self):
        self.entries = self._build_db()

    def search(self, query, top_k=3):
        q = self._normalize(query)
        q_words = set(q.split())
        scored = []
        for e in self.entries:
            kw = e.get("kw", [])
            matched = sum(1 for k in kw if k in q)
            if matched > 0:
                scored.append((matched, e))
        scored.sort(key=lambda x: -x[0])
        return [e for _, e in scored[:top_k]]

    def inject(self, query):
        results = self.search(query)
        if not results:
            return ""
        ctx = "\n\nالمعرفة المغربية:\n"
        for r in results:
            ctx += f"• {r['t']}: {r['c']}\n"
        return ctx

    @staticmethod
    def _normalize(t):
        t = unicodedata.normalize("NFKD", t.lower())
        t = re.sub(r"[^\w\s]", " ", t)
        return re.sub(r"\s+", " ", t).strip()

